import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    min_dist = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        dist_to_customer = np.linalg.norm(cur_truck_pos - customer)
        dist_to_depot = np.linalg.norm(customer - depot_pos)

        for truck_pos in all_truck_pos:
            dist_to_other_truck = np.linalg.norm(customer - truck_pos)
            dist_to_depot_other_truck = np.linalg.norm(truck_pos - depot_pos)

            if dist_to_other_truck >= dist_to_depot_other_truck:
                total_time = dist_to_customer + dist_to_depot
            else:
                total_time = dist_to_customer + dist_to_other_truck

            if total_time < min_dist:
                min_dist = total_time
                best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    avg_truck_pos = np.mean(all_truck_pos, axis=0)

    closest_customer_distance = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        dist_to_avg_truck_pos = calculate_distance(avg_truck_pos, customer_pos)
        dist_to_cur_truck_pos = calculate_distance(cur_truck_pos, customer_pos)

        total_distance = dist_to_avg_truck_pos + dist_to_cur_truck_pos
        if total_distance < closest_customer_distance:
            closest_customer_distance = total_distance
            best_node = i

    return best_node
